"use client";

import { Button, Drawer, useOverlayState } from "@heroui/react";
import { usePathname, useRouter } from "next/navigation";
import { navigationItems } from "./navigation-config";
import NavIcon from "./NavIcon";

interface MobileNavDrawerProps {
  isOpen: boolean;
  onOpenChange: (isOpen: boolean) => void;
}

export default function MobileNavDrawer({
  isOpen,
  onOpenChange,
}: MobileNavDrawerProps) {
  const pathname = usePathname();
  const router = useRouter();
  const drawerState = useOverlayState({
    isOpen,
    onOpenChange,
  });

  const handleNavigate = (href: string) => {
    drawerState.close();
    router.push(href);
  };

  return (
    <Drawer state={drawerState}>
      <Drawer.Backdrop className="lg:hidden" variant="opaque">
        <Drawer.Content className="lg:hidden" placement="left">
          <Drawer.Dialog className="h-full w-[var(--layout-sidebar-width)]">
            <Drawer.Header className="items-center justify-between border-b border-[var(--border)]">
              <Drawer.Heading>Sony Wiki</Drawer.Heading>
              <Drawer.CloseTrigger />
            </Drawer.Header>

            <Drawer.Body className="space-y-2 p-3">
              {navigationItems.map((item) => {
                const isActive = pathname?.startsWith(item.href);
                return (
                  <Button
                    key={item.href}
                    fullWidth
                    className="justify-start"
                    variant={isActive ? "primary" : "tertiary"}
                    onPress={() => handleNavigate(item.href)}
                  >
                    <NavIcon type={item.icon} className="size-4" />
                    <span>{item.label}</span>
                  </Button>
                );
              })}
            </Drawer.Body>
          </Drawer.Dialog>
        </Drawer.Content>
      </Drawer.Backdrop>
    </Drawer>
  );
}
