"use client";

import { useState } from "react";
import TopNavigation from "./TopNavigation";
import LenisSmoothScroll from "@/components/scroll/LenisSmoothScroll";
import ScrollTop from "@/components/scroll/ScrollTop";
import SidebarNavigation from "./SidebarNavigation";
import MobileNavDrawer from "./MobileNavDrawer";

interface ClientLayoutProps {
  children: React.ReactNode;
}

export default function ClientLayout({ children }: ClientLayoutProps) {
  const [isMobileNavigationOpen, setIsMobileNavigationOpen] = useState(false);

  return (
    <>
      <SidebarNavigation />
      <MobileNavDrawer
        isOpen={isMobileNavigationOpen}
        onOpenChange={setIsMobileNavigationOpen}
      />

      <div className="min-h-screen lg:pl-[var(--layout-sidebar-width)]">
        <TopNavigation onMenuPress={() => setIsMobileNavigationOpen(true)} />

        <main className="p-4 lg:p-6">
          {children}
        </main>
      </div>

      <ScrollTop />
      <LenisSmoothScroll />
    </>
  );
}
