"use client";

import { Avatar, Button, Spinner } from "@heroui/react";
import NavIcon from "./NavIcon";
import { AuthSlotProps } from "@/types/navigation";

export default function AuthSlot({
  state,
  user,
  onSignInRequest,
  onSignOutRequest,
}: AuthSlotProps) {
  if (state === "loading") {
    return (
      <Button isDisabled variant="secondary">
        <Spinner size="sm" />
        <span>Đang tải...</span>
      </Button>
    );
  }

  if (state === "authenticated") {
    return (
      <div className="flex items-center gap-2">
        <Avatar size="sm">
          {user?.avatarUrl ? (
            <Avatar.Image alt={user?.name ?? "Người dùng"} src={user.avatarUrl} />
          ) : null}
          <Avatar.Fallback>{user?.name?.slice(0, 1).toUpperCase() ?? "U"}</Avatar.Fallback>
        </Avatar>
        <Button variant="secondary" onPress={onSignOutRequest}>
          Đăng xuất
        </Button>
      </div>
    );
  }

  return (
    <Button variant="secondary" onPress={onSignInRequest}>
      <NavIcon type="google" className="size-4" />
      <span>Sign in with Google</span>
    </Button>
  );
}
