"use client";

import { Button } from "@heroui/react";
import { usePathname, useRouter } from "next/navigation";
import { navigationItems } from "./navigation-config";
import NavIcon from "./NavIcon";

export default function SidebarNavigation() {
  const pathname = usePathname();
  const router = useRouter();

  return (
    <aside
      className="fixed inset-y-0 left-0 z-40 hidden w-[var(--layout-sidebar-width)] border-r border-[var(--border)] bg-[var(--surface)] lg:flex lg:flex-col"
      aria-label="Sidebar navigation"
    >
      <div className="flex h-[var(--layout-header-height)] items-center gap-3 border-b border-[var(--border)] px-5">
        <div className="flex h-8 w-8 items-center justify-center rounded-lg bg-[var(--primary)] text-[var(--primary-foreground)] text-sm font-bold">
          SW
        </div>
        <span className="text-base font-semibold text-[var(--foreground)]">Sony Wiki</span>
      </div>

      <nav className="flex-1 space-y-2 p-3">
        {navigationItems.map((item) => {
          const isActive = pathname?.startsWith(item.href);
          return (
            <Button
              key={item.href}
              fullWidth
              className="justify-start"
              variant={isActive ? "primary" : "tertiary"}
              onPress={() => router.push(item.href)}
            >
              <NavIcon type={item.icon} className="size-4" />
              <span>{item.label}</span>
            </Button>
          );
        })}
      </nav>

      <div className="border-t border-[var(--border)] px-4 py-3 text-xs text-[var(--muted-foreground)]">
        Sony Wiki v1.0
      </div>
    </aside>
  );
}
